import React, { useEffect, useRef } from 'react';

function DottedSphere({ size = 600, className = '' }) {
  const canvasRef = useRef(null);
  const animationRef = useRef(null);
  const angleRef = useRef(0);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    const centerX = size / 2;
    const centerY = size / 2;
    const radius = size / 2.5;

    const numLatitudes = 18;
    const numLongitudes = 36;

    function draw() {
      ctx.clearRect(0, 0, size, size);

      // Glow effect
      const gradient = ctx.createRadialGradient(centerX, centerY, 0, centerX, centerY, radius * 1.2);
      gradient.addColorStop(0, 'rgba(139, 92, 246, 0.2)');
      gradient.addColorStop(0.5, 'rgba(99, 102, 241, 0.1)');
      gradient.addColorStop(1, 'rgba(59, 130, 246, 0)');
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, size, size);

      const dots = [];
      const rotationY = angleRef.current;

      // Generate dots on sphere surface
      for (let lat = 0; lat <= numLatitudes; lat++) {
        const theta = (lat / numLatitudes) * Math.PI;
        const sinTheta = Math.sin(theta);
        const cosTheta = Math.cos(theta);

        const dotsInRing = Math.max(1, Math.floor(numLongitudes * sinTheta));

        for (let lon = 0; lon < dotsInRing; lon++) {
          const phi = (lon / dotsInRing) * Math.PI * 2 + rotationY;

          // 3D coordinates
          const x = radius * sinTheta * Math.cos(phi);
          const y = radius * cosTheta;
          const z = radius * sinTheta * Math.sin(phi);

          // Only show front half (z > -radius * 0.3)
          const depth = (z + radius) / (2 * radius);

          // Project to 2D
          const projX = centerX + x;
          const projY = centerY + y;

          dots.push({ x: projX, y: projY, z, depth });
        }
      }

      // Sort by depth (back to front)
      dots.sort((a, b) => a.z - b.z);

      // Draw dots
      dots.forEach(dot => {
        const alpha = 0.2 + dot.depth * 0.6;
        const dotSize = 1.5 + dot.depth * 2;

        ctx.beginPath();
        ctx.arc(dot.x, dot.y, dotSize, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(167, 139, 250, ${alpha})`;
        ctx.fill();
      });

      angleRef.current += 0.003;
      animationRef.current = requestAnimationFrame(draw);
    }

    draw();

    return () => {
      if (animationRef.current) {
        cancelAnimationFrame(animationRef.current);
      }
    };
  }, [size]);

  return (
    <div className={`absolute pointer-events-none ${className}`} style={{
      width: size,
      height: size,
    }}>
      <canvas 
        ref={canvasRef} 
        width={size} 
        height={size}
        style={{ width: size, height: size }}
      />
    </div>
  );
}

export default DottedSphere;
